import { isNil } from 'lodash-es';
import { createContext, useContext } from 'react';

import { Dimensions } from '../../../types/dimensions.js';

export interface TooltipDimensionsContextValue {
  containerRef: HTMLDivElement | null;
}

export const TooltipDimensionsContext = createContext<Dimensions | null>(null);

export const useTooltipDimensions = () => {
  const context = useContext(TooltipDimensionsContext);

  if (isNil(context)) {
    return null;
  }

  return context;
};
